module top_module(
    input [15:0] obf_input_signal,
    output reg [1:0] output_signal
);always @(*) begin
    if (obf_input_signal < 1000) begin
        output_signal = 2'b01;
    end else if (obf_input_signal >= 1000 && obf_input_signal <= 2000) begin
        output_signal = 2'b10;
    end else if (obf_input_signal > 2000) begin
        output_signal = 2'b11;
    end
end

endmodule
